(window.webpackJsonp=window.webpackJsonp||[]).push([[951],{923:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">customers</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> averageWaitingTime = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">customers</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> curTime=customers[<span class=\\"hljs-number\\">0</span>][<span class=\\"hljs-number\\">0</span>]\\n    <span class=\\"hljs-keyword\\">let</span> waitTime=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> [arrived,consume] <span class=\\"hljs-keyword\\">of</span> customers){\\n        curTime=<span class=\\"hljs-built_in\\">Math</span>.max(curTime,arrived)\\n        curTime+=consume\\n        waitTime+=curTime - arrived\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> waitTime / customers.length\\n};\\n</code></pre>\\n"],"titleSlug":"average-waiting-time","hasThinking":false,"content":"<p>\u6709\u4e00\u4e2a\u9910\u5385\uff0c\u53ea\u6709\u4e00\u4f4d\u53a8\u5e08\u3002\u4f60\u6709\u4e00\u4e2a\u987e\u5ba2\u6570\u7ec4\xa0<code>customers</code>\xa0\uff0c\u5176\u4e2d\xa0<code>customers[i] = [arrival<sub>i</sub>, time<sub>i</sub>]</code>\xa0\uff1a</p>\\n\\n<ul>\\n\\t<li><code>arrival<sub>i</sub></code>\xa0\u662f\u7b2c\xa0<code>i</code>\xa0\u4f4d\u987e\u5ba2\u5230\u8fbe\u7684\u65f6\u95f4\uff0c\u5230\u8fbe\u65f6\u95f4\u6309 <strong>\u975e\u9012\u51cf</strong> \u987a\u5e8f\u6392\u5217\u3002</li>\\n\\t<li><code>time<sub>i</sub></code>\xa0\u662f\u7ed9\u7b2c <code>i</code>\xa0\u4f4d\u987e\u5ba2\u505a\u83dc\u9700\u8981\u7684\u65f6\u95f4\u3002</li>\\n</ul>\\n\\n<p>\u5f53\u4e00\u4f4d\u987e\u5ba2\u5230\u8fbe\u65f6\uff0c\u4ed6\u5c06\u4ed6\u7684\u8ba2\u5355\u7ed9\u53a8\u5e08\uff0c\u53a8\u5e08\u4e00\u65e6\u7a7a\u95f2\u7684\u65f6\u5019\u5c31\u5f00\u59cb\u505a\u8fd9\u4f4d\u987e\u5ba2\u7684\u83dc\u3002\u6bcf\u4f4d\u987e\u5ba2\u4f1a\u4e00\u76f4\u7b49\u5f85\u5230\u53a8\u5e08\u5b8c\u6210\u4ed6\u7684\u8ba2\u5355\u3002\u53a8\u5e08\u540c\u65f6\u53ea\u80fd\u505a\u4e00\u4e2a\u4eba\u7684\u8ba2\u5355\u3002\u53a8\u5e08\u4f1a\u4e25\u683c\u6309\u7167 <strong>\u8ba2\u5355\u7ed9\u4ed6\u7684\u987a\u5e8f</strong>\xa0\u505a\u83dc\u3002</p>\\n\\n<p>\u8bf7\u4f60\u8fd4\u56de\u6240\u6709\u987e\u5ba2\u9700\u8981\u7b49\u5f85\u7684 <strong>\u5e73\u5747\xa0</strong>\u65f6\u95f4\u3002\u4e0e\u6807\u51c6\u7b54\u6848\u8bef\u5dee\u5728\xa0<code>10<sup>-5</sup></code>\xa0\u8303\u56f4\u4ee5\u5185\uff0c\u90fd\u89c6\u4e3a\u6b63\u786e\u7ed3\u679c\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<b>\u8f93\u5165\uff1a</b>customers = [[1,2],[2,5],[4,3]]\\n<b>\u8f93\u51fa\uff1a</b>5.00000\\n<strong>\u89e3\u91ca\uff1a\\n</strong>1) \u7b2c\u4e00\u4f4d\u987e\u5ba2\u5728\u65f6\u523b 1 \u5230\u8fbe\uff0c\u53a8\u5e08\u62ff\u5230\u4ed6\u7684\u8ba2\u5355\u5e76\u5728\u65f6\u523b 1 \u7acb\u9a6c\u5f00\u59cb\u505a\u83dc\uff0c\u5e76\u5728\u65f6\u523b 3 \u5b8c\u6210\uff0c\u7b2c\u4e00\u4f4d\u987e\u5ba2\u7b49\u5f85\u65f6\u95f4\u4e3a 3 - 1 = 2 \u3002\\n2) \u7b2c\u4e8c\u4f4d\u987e\u5ba2\u5728\u65f6\u523b 2 \u5230\u8fbe\uff0c\u53a8\u5e08\u5728\u65f6\u523b 3 \u5f00\u59cb\u4e3a\u4ed6\u505a\u83dc\uff0c\u5e76\u5728\u65f6\u523b 8 \u5b8c\u6210\uff0c\u7b2c\u4e8c\u4f4d\u987e\u5ba2\u7b49\u5f85\u65f6\u95f4\u4e3a 8 - 2 = 6 \u3002\\n3) \u7b2c\u4e09\u4f4d\u987e\u5ba2\u5728\u65f6\u523b 4 \u5230\u8fbe\uff0c\u53a8\u5e08\u5728\u65f6\u523b 8 \u5f00\u59cb\u4e3a\u4ed6\u505a\u83dc\uff0c\u5e76\u5728\u65f6\u523b 11 \u5b8c\u6210\uff0c\u7b2c\u4e09\u4f4d\u987e\u5ba2\u7b49\u5f85\u65f6\u95f4\u4e3a 11 - 4 = 7 \u3002\\n\u5e73\u5747\u7b49\u5f85\u65f6\u95f4\u4e3a (2 + 6 + 7) / 3 = 5 \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<b>\u8f93\u5165\uff1a</b>customers = [[5,2],[5,4],[10,3],[20,1]]\\n<b>\u8f93\u51fa\uff1a</b>3.25000\\n<strong>\u89e3\u91ca\uff1a\\n</strong>1) \u7b2c\u4e00\u4f4d\u987e\u5ba2\u5728\u65f6\u523b 5 \u5230\u8fbe\uff0c\u53a8\u5e08\u62ff\u5230\u4ed6\u7684\u8ba2\u5355\u5e76\u5728\u65f6\u523b 5 \u7acb\u9a6c\u5f00\u59cb\u505a\u83dc\uff0c\u5e76\u5728\u65f6\u523b 7 \u5b8c\u6210\uff0c\u7b2c\u4e00\u4f4d\u987e\u5ba2\u7b49\u5f85\u65f6\u95f4\u4e3a 7 - 5 = 2 \u3002\\n2) \u7b2c\u4e8c\u4f4d\u987e\u5ba2\u5728\u65f6\u523b 5 \u5230\u8fbe\uff0c\u53a8\u5e08\u5728\u65f6\u523b 7 \u5f00\u59cb\u4e3a\u4ed6\u505a\u83dc\uff0c\u5e76\u5728\u65f6\u523b 11 \u5b8c\u6210\uff0c\u7b2c\u4e8c\u4f4d\u987e\u5ba2\u7b49\u5f85\u65f6\u95f4\u4e3a 11 - 5 = 6 \u3002\\n3) \u7b2c\u4e09\u4f4d\u987e\u5ba2\u5728\u65f6\u523b 10 \u5230\u8fbe\uff0c\u53a8\u5e08\u5728\u65f6\u523b 11 \u5f00\u59cb\u4e3a\u4ed6\u505a\u83dc\uff0c\u5e76\u5728\u65f6\u523b 14 \u5b8c\u6210\uff0c\u7b2c\u4e09\u4f4d\u987e\u5ba2\u7b49\u5f85\u65f6\u95f4\u4e3a 14 - 10 = 4 \u3002\\n4) \u7b2c\u56db\u4f4d\u987e\u5ba2\u5728\u65f6\u523b 20 \u5230\u8fbe\uff0c\u53a8\u5e08\u62ff\u5230\u4ed6\u7684\u8ba2\u5355\u5e76\u5728\u65f6\u523b 20 \u7acb\u9a6c\u5f00\u59cb\u505a\u83dc\uff0c\u5e76\u5728\u65f6\u523b 21 \u5b8c\u6210\uff0c\u7b2c\u56db\u4f4d\u987e\u5ba2\u7b49\u5f85\u65f6\u95f4\u4e3a 21 - 20 = 1 \u3002\\n\u5e73\u5747\u7b49\u5f85\u65f6\u95f4\u4e3a (2 + 6 + 4 + 1) / 4 = 3.25 \u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= customers.length <= 10<sup>5</sup></code></li>\\n\\t<li><code>1 <= arrival<sub>i</sub>, time<sub>i</sub> <= 10<sup>4</sup></code></li>\\n\\t<li><code>arrival<sub>i\xa0</sub><= arrival<sub>i+1</sub></code></li>\\n</ul>\\n","title":"1701. \u5e73\u5747\u7b49\u5f85\u65f6\u95f4","relatedTags":["\u6570\u7ec4"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1701"}')}}]);